#include <iostream>
using namespace std;
int main()
{
    int l,m,u,v,sum=0;
    cin>>l>>m;
	bool a[10005];
	for(int c=0;c<=10005;c++)a[c]=true;
	for(int i=1;i<=m;i++)
	{
		cin>>u>>v;
		for(int j=u;j<=v;j++){
			a[j]=false;
		}
	}
	for(int k=0;k<=l;k++)
	{
		if(a[k]==true)sum++;
	}
	cout<<sum;
    return 0;
}
